function rateLimiter(pings) {
  const resultMap = new Map();

  const ans = [];

  for (let i = 0; i < pings.length; i++) {
    const [customerId, pingTime] = pings[i];

    if (!resultMap.has(customerId)) {
      resultMap.set(customerId, [pingTime]);
      ans.push(true);
    } else {
      const pingTimes = resultMap.get(customerId);
      const lastTwoPings = pingTimes.slice(-2);
      const timeDiff = pingTime - lastTwoPings[1];

      if (timeDiff < 1000) {
        ans.push(false);
      } else {
        pingTimes.push(pingTime);
        ans.push(true);
      }
    }
  }

  return ans;
}
